1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:   This module is used to sync a FWFT FIFO bus
5	--                either as a pass through or with pipeline register stages.
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	
19	library surf;
20	use surf.StdRtlPkg.all;
21	
22	entity FifoOutputPipeline is
23	   generic (
24	      TPD_G          : time                       := 1 ns;
25	      RST_POLARITY_G : sl                         := '1';  -- '1' for active high rst, '0' for active low
26	      RST_ASYNC_G    : boolean                    := false;
27	      DATA_WIDTH_G   : integer range 1 to (2**24) := 16;
28	      PIPE_STAGES_G  : natural range 0 to 16      := 1);
29	   port (
30	      -- Slave Port
31	      sData  : in  slv(DATA_WIDTH_G-1 downto 0);
32	      sValid : in  sl;
33	      sRdEn  : out sl;
34	      -- Master Port
35	      mData  : out slv(DATA_WIDTH_G-1 downto 0);
36	      mValid : out sl;
37	      mRdEn  : in  sl;
38	      -- Clock and Reset
39	      clk    : in  sl;
40	      rst    : in  sl := not RST_POLARITY_G);              -- Optional reset
41	end FifoOutputPipeline;
42	
43	architecture rtl of FifoOutputPipeline is
44	
45	   constant PIPE_STAGES_C : natural := PIPE_STAGES_G+1;
46	
47	   type DataArray is array (natural range <>) of slv(DATA_WIDTH_G-1 downto 0);
48	
49	   type RegType is record
50	      sRdEn  : sl;
51	      mValid : slv(0 to PIPE_STAGES_C);
52	      mData  : DataArray(0 to PIPE_STAGES_C);
53	   end record RegType;
54	
55	   constant REG_INIT_C : RegType := (
56	      sRdEn  => '0',
57	      mValid => (others => '0'),
58	      mData  => (others => (others => '0')));
59	
60	   signal r   : RegType := REG_INIT_C;
61	   signal rin : RegType;
62	
63	begin
64	
65	   ZERO_LATENCY : if (PIPE_STAGES_G = 0) generate
66	
67	      mData  <= sData;
68	      mValid <= sValid;
69	      sRdEn  <= mRdEn;
70	
71	   end generate;
72	
73	   PIPE_REG : if (PIPE_STAGES_G > 0) generate
74	
75	      comb : process (mRdEn, r, rst, sData, sValid) is
76	         variable v : RegType;
77	      begin
78	         -- Latch the current value
79	         v := r;
80	
81	         -- Check if we need to shift register
82	         if (r.mValid(PIPE_STAGES_C) = '0') or (mRdEn = '1') then
83	            -- Shift the data up the pipeline
84	            for i in PIPE_STAGES_C downto 2 loop
85	               v.mValid(i) := r.mValid(i-1);
86	               v.mData(i)  := r.mData(i-1);
87	            end loop;
88	
89	            -- Check if the lowest cell is empty
90	            if r.mValid(0) = '0' then
91	               -- Set the read bit
92	               v.sRdEn := '1';
93	               -- Check if we were pulling the FIFO last clock cycle
94	               if r.sRdEn = '1' then
95	                  -- Shift the FIFO data
96	                  v.mValid(1) := sValid;
97	                  v.mData(1)  := sData;
98	               else
99	                  -- Clear valid in stage 1
100	                  v.mValid(1) := '0';
101	               end if;
102	            else
103	               -- Shift the lowest cell
104	               v.mValid(1) := r.mValid(0);
105	               v.mData(1)  := r.mData(0);
106	               -- Check if we were pulling the FIFO last clock cycle
107	               if r.sRdEn = '1' then
108	                  -- Reset the read bit
109	                  v.sRdEn     := '0';
110	                  -- Fill the lowest cell
111	                  v.mValid(0) := sValid;
112	                  v.mData(0)  := sData;
113	               else
114	                  -- Set the read bit
115	                  v.sRdEn     := '1';
116	                  -- Reset the lowest cell mValid
117	                  v.mValid(0) := '0';
118	               end if;
119	            end if;
120	         else
121	            -- Reset the read bit
122	            v.sRdEn := '0';
123	            -- Check if we were pulling the FIFO last clock cycle
124	            if r.sRdEn = '1' then
125	               -- Fill the lowest cell
126	               v.mValid(0) := sValid;
127	               v.mData(0)  := sData;
128	            elsif r.mValid(0) = '0' then
129	               -- Set the read bit
130	               v.sRdEn := '1';
131	            end if;
132	            -- Check if we need to internally shift the data to remove gaps
133	            for i in PIPE_STAGES_C-1 downto 1 loop
134	               -- Check for empty cell ahead of a filled cell
135	               if (r.mValid(i) = '0') and (r.mValid(i-1) = '1') then
136	                  -- Shift the lowest cell
137	                  v.mValid(i)   := r.mValid(i-1);
138	                  v.mData(i)    := r.mData(i-1);
139	                  -- Reset the flag
140	                  v.mValid(i-1) := '0';
141	               end if;
142	            end loop;
143	         end if;
144	
145	         -- Synchronous Reset
146	         if (RST_ASYNC_G = false and rst = RST_POLARITY_G) then
147	            v := REG_INIT_C;
148	         end if;
149	
150	         -- Register the variable for next clock cycle
151	         rin <= v;
152	
153	         -- Outputs
154	         sRdEn  <= r.sRdEn;
155	         mValid <= r.mValid(PIPE_STAGES_C);
156	         mData  <= r.mData(PIPE_STAGES_C);
157	
158	      end process comb;
159	
160	      seq : process (clk, rst) is
161	      begin
162	         if (RST_ASYNC_G and rst = RST_POLARITY_G) then
163	            r <= REG_INIT_C after TPD_G;
164	         elsif rising_edge(clk) then
165	            r <= rin after TPD_G;
166	         end if;
167	      end process seq;
168	
169	   end generate;
170	
171	end rtl;
172

