140	            -- Check for BRAM (2 cycle read latency = DOB_REG_G + Internal REG )
141	            if (MEMORY_TYPE_G /= "distributed") then
142	
143	               -- Check if we need to move data from RAM output to RAM REG
144	               if (v.tValid(1) = '0') and (r.tValid(0) = '1') then
145	                  -- Move the data into the RAM REG
