147	                  v.tValid(1) := '1';
148	                  v.tValid(0) := '0';
149	               end if;
150	
151	               -- Check if able to move pipeline and FIFO is not empty
152	               if (v.tValid(0) = '0') and (r.empty = '0') then
153	                  -- Move the flag
154	                  v.enb       := '1';
155	                  v.tValid(0) := '1';
156	                  -- Increment the read address
157	                  v.rdAddr    := r.rdAddr + 1;
158	               end if;
159	
160	            -- Else LUTRAM (1 cycle read latency = Internal REG)
161	            else
162	
163	               -- Check if able to move pipeline and FIFO is not empty
164	               if (v.tValid(1) = '0') and (r.empty = '0') then
165	                  -- Move the flag
166	                  v.enb       := '1';
167	                  v.tValid(1) := '1';
168	                  -- Increment the read address
169	                  v.rdAddr    := r.rdAddr + 1;
170	               end if;
171	
172	            end if;
173	
174	         else
175	
176	            -----------------------------------------
177	            --             FIFO Mode
178	            -----------------------------------------
179	
180	            -- Check for read operation
181	            if (rd_en = '1') then
182	
183	               -- Check if FIFO is not empty
184	               if (r.empty = '0') then
