191	
192	               -- Else Underflow detected
193	               else
194	
195	                  -- Set the flag
196	                  v.underflow := '1';
197	
198	               end if;
199	
200	            end if;
201	
202	            -- Unused signals in FIFO mode
203	            v.enb    := '1';
204	            v.regceb := '1';
205	
206	         end if;
207	
208	         -- Update the count
209	         v.count := wrAddr - v.rdAddr;
210	
211	      end if;
212	
213	      -----------------------------------------
214	      --       Update flags
215	      -----------------------------------------
216	
217	      -- Update the empty flag
218	      if (v.count = 0) then
219	         v.empty := '1';
220	      else
221	         v.empty := '0';
222	      end if;
223	
224	      -- Update the almost_empty flag
